const fields = $json?.data?.items || [];
const config = $('配置参数').item.json;
const token = $('获取飞书 Tenant Token').item.json.tenant_access_token;

const platformField = fields.find(f => 
  f.field_name.toUpperCase().includes('SOCIAL MEDIA PLATFORM') || 
  f.field_name.toUpperCase().includes('PLATFORM') ||
  f.field_name.includes('平台')
);

const linkField = fields.find(f => 
  f.field_name.toUpperCase().includes('POSTS LINK') || 
  f.field_name.toUpperCase().includes('LINK') ||
  f.field_name.includes('链接') ||
  f.field_name.includes('URL')
);

const fieldConfig = {
  platformFieldName: platformField?.field_name || 'SOCIAL MEDIA PLATFORM',
  linkFieldName: linkField?.field_name || 'POSTS Link',
  allFields: fields.map(f => ({
    name: f.field_name,
    type: f.type,
    ui_type: f.ui_type,
    field_id: f.field_id
  }))
};

return {
  json: {
    ...config,
    tenant_access_token: token,
    fieldConfig
  }
};

// 从当前节点获取记录数据
const records = $json?.data?.items || [];

// 从上游节点获取字段配置
let prevData = {};
try {
  prevData = $('处理字段配置').first().json || {};
} catch (e) {
  prevData = {};
}

const platformField = prevData.fieldConfig?.platformFieldName || 'SOCIAL MEDIA PLATFORM';
const linkField = prevData.fieldConfig?.linkFieldName || 'POSTS Link';
const tenantToken = prevData.tenant_access_token || '';
const bitableToken = prevData.bitableToken || '';
const sheetId = prevData.sheetId || '';

const platformGroups = {
  INSTAGRAM: [],
  X: [],
  FACEBOOK: [],
  YOUTUBE: [],
  DISCORD: [],
  UNKNOWN: []
};

for (const record of records) {
  const fields = record.fields || {};
  const platform = String(fields[platformField] || '').toUpperCase().trim();
  const link = fields[linkField] || '';

  const recordData = {
    record_id: record.record_id,
    platform: platform,
    link: link,
    fields: fields
  };

  if (platform.includes('INSTAGRAM') || platform.includes('INS')) {
    platformGroups.INSTAGRAM.push(recordData);
  } else if (platform.includes('X') || platform.includes('TWITTER')) {
    platformGroups.X.push(recordData);
  } else if (platform.includes('YOUTUBE') || platform.includes('YT')) {
    platformGroups.YOUTUBE.push(recordData);
  } else if (platform.includes('FACEBOOK') || platform.includes('FB') || platform.includes('facebook')) {
    platformGroups.FACEBOOK.push(recordData);
  } else if (platform.includes('DISCORD')) {
    platformGroups.DISCORD.push(recordData);
  } else {
    platformGroups.UNKNOWN.push(recordData);
  }
}

return {
  json: {
    bitableToken,
    sheetId,
    tenant_access_token: tenantToken,
    fieldConfig: prevData.fieldConfig,
    platformGroups,
    totalRecords: records.length
  }
};

const data = $('按平台分组记录').item.json;
const platformGroups = data.platformGroups;

const results = [];

if (platformGroups.INSTAGRAM.length > 0) {
  results.push({
    json: {
      platform: 'INSTAGRAM',
      records: platformGroups.INSTAGRAM,
      bitableToken: data.bitableToken,
      sheetId: data.sheetId,
      tenant_access_token: data.tenant_access_token,
      fieldConfig: data.fieldConfig
    }
  });
}

if (platformGroups.X.length > 0) {
  results.push({
    json: {
      platform: 'X',
      records: platformGroups.X,
      bitableToken: data.bitableToken,
      sheetId: data.sheetId,
      tenant_access_token: data.tenant_access_token,
      fieldConfig: data.fieldConfig
    }
  });
}

if (platformGroups.YOUTUBE.length > 0) {
  results.push({
    json: {
      platform: 'YOUTUBE',
      records: platformGroups.YOUTUBE,
      bitableToken: data.bitableToken,
      sheetId: data.sheetId,
      tenant_access_token: data.tenant_access_token,
      fieldConfig: data.fieldConfig
    }
  });
}

if (platformGroups.FACEBOOK.length > 0) {
  results.push({
    json: {
      platform: 'FACEBOOK',
      records: platformGroups.FACEBOOK,
      bitableToken: data.bitableToken,
      sheetId: data.sheetId,
      tenant_access_token: data.tenant_access_token,
      fieldConfig: data.fieldConfig
    }
  });
}

if (platformGroups.DISCORD.length > 0) {
  results.push({
    json: {
      platform: 'DISCORD',
      records: platformGroups.DISCORD,
      bitableToken: data.bitableToken,
      sheetId: data.sheetId,
      tenant_access_token: data.tenant_access_token,
      fieldConfig: data.fieldConfig
    }
  });
}

return results;

const inputData = $json;
const records = inputData.records || [];

const processedRecords = records.map(record => ({
  record_id: record.record_id,
  link: record.link,
}));

const apifyConfig = {
  directUrls: records.map(r => r.link.link).filter(link => link)
};

return {
  json: {
    platform: inputData.platform,
    processedRecords,
    apifyConfig,
    bitableToken: inputData.bitableToken,
    sheetId: inputData.sheetId,
    tenant_access_token: inputData.tenant_access_token,
    fieldConfig: inputData.fieldConfig
  }
};

const scraperData = $('Instagram Scraper').all().map(i => i.json);
const upstreamData = $('Instagram 数据处理').first().json;
const records = upstreamData.processedRecords || [];
const allFields = upstreamData.fieldConfig?.allFields || [];

// 辅助函数：模糊匹配字段项
function findFieldConfig(targetName, allFields) {
  const targetUpper = targetName.toUpperCase();
  const match = allFields.find(f => f.name.toUpperCase().includes(targetUpper));
  return match ? match : null;
}

// 获取实际字段名
const likesFieldConfig = findFieldConfig('LIKES', allFields);
const likesField = likesFieldConfig ? likesFieldConfig.name : null;
const commentsFieldConfig = findFieldConfig('COMMENTS', allFields);
const commentsField = commentsFieldConfig ? commentsFieldConfig.name : null;
const impressionsFieldConfig = findFieldConfig('IMPRESSIONS', allFields)
const impressionsField = impressionsFieldConfig ? impressionsFieldConfig.name : null;
const sharesFieldConfig = findFieldConfig('SHARES', allFields);
const sharesField = sharesFieldConfig ? sharesFieldConfig.name : null;
const tagsFieldConfig = findFieldConfig('TAGS', allFields);
const tagsField = tagsFieldConfig ? tagsFieldConfig.name : null

const results = [];
for (const scraped of scraperData) {
  const scraperUrl = String(scraped.inputUrl || '');
  if (!scraperUrl) continue;

  const matched = records.find(r => {
    const originalLink = String((r.link && r.link.link) || r.link || '');
    return originalLink && scraperUrl.includes(originalLink);
  });
  if (!matched) continue;

  const fields = {};
  if (scraped.likesCount !== undefined && likesField) {
    const isNumber = likesFieldConfig.ui_type === "Number";
    fields[likesField] = isNumber ? scraped.likesCount : scraped.likesCount.toString();
  }
  if (scraped.commentsCount !== undefined && commentsField) {
    const isNumber = commentsFieldConfig.ui_type === "Number";
    fields[commentsField] = isNumber ? scraped.commentsCount : scraped.commentsCount.toString();
  } 
if ((scraped.videoViewCount !== undefined || scraped.videoPlayCount !== undefined) && impressionsField) {
    const isNumber = impressionsFieldConfig.ui_type === "Number";
    const value = scraped.videoViewCount !== undefined ? scraped.videoViewCount : scraped.videoPlayCount;
    fields[impressionsField] = isNumber ? value : value.toString();
}

if (scraped.sharesCount !== undefined && sharesField) {
    const isNumber = sharesFieldConfig.ui_type === "Number";
    fields[sharesField] = isNumber ? scraped.sharesCount : scraped.sharesCount.toString();
}
  if (scraped.hashtags !== undefined && tagsField && tagsFieldConfig !==null) {
    fields[tagsField] = {
      link: scraped.inputUrl,
      text: scraped.hashtags.map(item => `#${item}`).join(' ')
    }
  }

  results.push({
    json: {
      bitableToken: upstreamData.bitableToken,
      sheetId: upstreamData.sheetId,
      tenant_access_token: upstreamData.tenant_access_token,
      recordId: matched.record_id,
      fields: fields
    }
  });
}

if (results.length === 0) {
  return [{ json: { _skip: true, message: 'Instagram: 无匹配记录需要更新' } }];
}
return results;

const ok = $json?.code === 0 || $json?.msg === 'success';
return {
  success: ok,
  recordId: $json?.data?.record?.record_id || null,
  raw: $json
};
